class Solution:
    def arrayPairSum(self, nums):
        nums.sort()
        return sum(nums[::2])

solutions.javascript:
var arrayPairSum = function(nums) {
    nums.sort((a, b) => a - b);
    let total = 0;
    for (let i = 0; i < nums.length; i += 2) total += nums[i];
    return total;
};
